mapper.select:
SELECT
    t.ID, t.THEME_NAME, t.THEME_TYPE, t.OWNER_TYPE, t.OWNER_ID, u.USERNAME AS OWNER_NAME,
    t.IS_DEFAULT, t.IS_ACTIVE, t.PREVIEW_COVER, t.DESCRIPTION
FROM theme t
LEFT JOIN user u ON u.ID = t.OWNER_ID



        AND t.THEME_NAME LIKE #{themeNameBind}


        AND t.THEME_TYPE = #{query.themeType}


        AND t.OWNER_TYPE = #{query.ownerType}



        AND u.USERNAME LIKE #{ownerNameBind}


        AND t.IS_DEFAULT = #{query.isDefault}


        AND t.IS_ACTIVE = #{query.isActive}


ORDER BY COALESCE(t.UPDATE_TIME, t.CREATE_TIME) DESC

mapper.update:
UPDATE theme SET
    THEME_NAME = #{t.themeName}, DESCRIPTION = #{t.description}, PREVIEW_COVER = #{t.previewCover},
    UPDATE_USER = #{t.updateUser}, UPDATE_TIME = #{t.updateTime}
WHERE ID = #{t.id}
